#include<bits/stdc++.h>
using namespace std;
long long root[200010];
struct node
{
    long long lson,rson;
    long long sum;
}a[6000010];
stack<long long> s;
long long tot,n,m;
long long newnode()
{
    if(s.empty())
    {
        return ++tot;
    }
    long long ans=s.top();
    s.pop();
    return ans;
}
void delnode(long long x)
{
    s.push(x);
    a[x].lson=a[x].rson=a[x].sum=0;
}
void update(long long &x,long long l,long long r,long long p,long long val)
{
    if(!x)
    {
        x=newnode();
    }
    a[x].sum+=val;
    if(l==r)
    {
        return;
    }
    long long mid=(l+r)>>1;
    if(p<=mid)
    {
        update(a[x].lson,l,mid,p,val);
    }
    else
    {
        update(a[x].rson,mid+1,r,p,val);
    }
}
long long kth(long long x,long long l,long long r,long long k)
{
    if(l==r)
    {
        return l; 
    }
    long long mid=(l+r)>>1;
    if(a[a[x].lson].sum>=k)
    {
        return kth(a[x].lson,l,mid,k);
    }
    else
    {
        return kth(a[x].rson,mid+1,r,k-a[a[x].lson].sum);
    }
}
long long getsum(long long x,long long l,long long r,long long u,long long v)
{
    if(l>v||r<u||x==0)
    {
        return 0;
    }
    if(u<=l&&r<=v)
    {
        return a[x].sum;
    }
    long long mid=(l+r)>>1;
    return getsum(a[x].lson,l,mid,u,v)+getsum(a[x].rson,mid+1,r,u,v);
}
void split(long long x,long long &y,long long k)
{
    if(x==0)
    {
        return;
    }
    y=newnode();
    long long v=a[a[x].lson].sum;
    if(k>v)
    {
        split(a[x].rson,a[y].rson,k-v);
    }
    else
    {
        swap(a[x].rson,a[y].rson);
    }
    if(k<v)
    {
        split(a[x].lson,a[y].lson,k);
    }
    a[y].sum=a[x].sum-k;
    a[x].sum=k;
}
long long merge(long long x,long long y)
{
    if(x==0||y==0)
    {
        return x+y;
    }
    a[x].sum+=a[y].sum;
    a[x].lson=merge(a[x].lson,a[y].lson);
    a[x].rson=merge(a[x].rson,a[y].rson);
    delnode(y);
    return x;
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        update(root[1],1,n,i,x);
    }
    long long tot1=1;
    while(m--)
    {
        long long op;
        scanf("%lld",&op);
        if(op==0)
        {
            long long x,y,z;
            scanf("%lld%lld%lld",&x,&y,&z);
            long long k1=getsum(root[x],1,n,1,z),k2=getsum(root[x],1,n,y,z);
            long long tmp=0;
            split(root[x],root[++tot1],k1-k2);
            split(root[tot1],tmp,k2);
            root[x]=merge(root[x],tmp);
        }
        else if(op==1)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            root[x]=merge(root[x],root[y]);
        }
        else if(op==2)
        {
            long long x,y,z;
            scanf("%lld%lld%lld",&x,&y,&z);
            update(root[x],1,n,z,y);
        }
        else if(op==3)
        {
            long long x,y,z;
            scanf("%lld%lld%lld",&x,&y,&z);
            printf("%lld\n",getsum(root[x],1,n,y,z));
        }
        else
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            if(a[root[x]].sum<y)
            {
                printf("-1\n");
                continue;
            }
            printf("%lld\n",kth(root[x],1,n,y));
        }
    }
    return 0;
}
